// Parse Pas de Deux iCal feed
const ical = $input.first().json.data || '';
const events = [];
const blocks = ical.split('BEGIN:VEVENT');

for (let i = 1; i < blocks.length; i++) {
  const block = blocks[i];
  const get = (key) => {
    const m = block.match(new RegExp(key + '[:;]([^\\n]+)'));
    return m ? m[1].replace(/^.*:/, '').trim() : '';
  };

  let dtstart = get('DTSTART');
  // Parse date: 20260415T193000Z or 20260415
  let date = '';
  let time = '';
  if (dtstart.length >= 8) {
    date = dtstart.substring(0,4) + '-' + dtstart.substring(4,6) + '-' + dtstart.substring(6,8);
    if (dtstart.length >= 13) {
      time = dtstart.substring(9,11) + ':' + dtstart.substring(11,13);
    }
  }

  const title = get('SUMMARY').replace(/\\,/g, ',').replace(/\\n/g, ' ');
  const desc = get('DESCRIPTION').replace(/\\,/g, ',').replace(/\\n/g, ' ').substring(0, 300);
  const location = get('LOCATION').replace(/\\,/g, ',');

  if (title && date && date >= new Date().toISOString().slice(0,10)) {
    events.push({
      title: title,
      event_date: date,
      event_time: time,
      city: 'Lisbon',
      description: desc || 'Dancing event at Pas de Deux',
      category: 'social',
      source: 'Pas de Deux',
      url: 'https://pasdedeux.pt/',
      status: 'approved'
    });
  }
}

return events.slice(0, 30).map(e => ({ json: e }));

// Parse Eventbrite API response
const data = $input.first().json;
const events = [];

try {
  const results = data.events?.results || data.events || [];
  for (const e of results) {
    const title = e.name || e.title || '';
    const startDate = e.start_date || e.primary_venue?.address?.localized_date_display || '';
    const url = e.url || (e.id ? 'https://www.eventbrite.com/e/' + e.id : '');
    const desc = (e.summary || e.description?.text || '').substring(0, 300);

    // Try to parse date
    let date = '';
    if (e.start_date) {
      date = e.start_date;
    } else if (e.start?.utc) {
      date = e.start.utc.substring(0, 10);
    }

    let time = '';
    if (e.start?.local) {
      time = e.start.local.substring(11, 16);
    }

    // Determine category
    let cat = 'social';
    const lower = title.toLowerCase();
    if (lower.includes('music') || lower.includes('fado') || lower.includes('concert') || lower.includes('dj')) cat = 'music';
    else if (lower.includes('food') || lower.includes('cook') || lower.includes('wine') || lower.includes('dinner') || lower.includes('brunch')) cat = 'food';
    else if (lower.includes('art') || lower.includes('exhibition') || lower.includes('gallery') || lower.includes('ceramic')) cat = 'art';
    else if (lower.includes('market') || lower.includes('feira') || lower.includes('mercado')) cat = 'market';
    else if (lower.includes('family') || lower.includes('kids') || lower.includes('children')) cat = 'family';
    else if (lower.includes('yoga') || lower.includes('fitness') || lower.includes('run') || lower.includes('sport') || lower.includes('surf')) cat = 'sport';
    else if (lower.includes('culture') || lower.includes('tour') || lower.includes('walk') || lower.includes('history')) cat = 'culture';

    if (title && date) {
      events.push({
        title: title.substring(0, 200),
        event_date: date,
        event_time: time,
        city: 'Lisbon',
        description: desc,
        category: cat,
        source: 'Eventbrite',
        url: url,
        status: 'approved'
      });
    }
  }
} catch(err) {
  // If API structure changed, return empty
}

return events.slice(0, 40).map(e => ({ json: e }));

// Parse Gulbenkian agenda page (HTML scraping)
const html = $input.first().json.data || '';
const events = [];

// Look for event patterns in HTML
const titleMatches = html.match(/<h[23][^>]*class="[^"]*title[^"]*"[^>]*>([^<]+)/gi) || [];
const linkMatches = html.match(/href="(\/en\/agenda\/[^"]+)"/gi) || [];

for (let i = 0; i < Math.min(titleMatches.length, 20); i++) {
  const titleMatch = titleMatches[i].match(/>([^<]+)/);
  const linkMatch = linkMatches[i] ? linkMatches[i].match(/href="([^"]+)"/) : null;

  if (titleMatch) {
    events.push({
      title: titleMatch[1].trim().substring(0, 200),
      event_date: new Date().toISOString().slice(0, 10),
      city: 'Lisbon',
      description: 'Event at Gulbenkian Foundation',
      category: 'culture',
      source: 'Gulbenkian',
      url: linkMatch ? 'https://gulbenkian.pt' + linkMatch[1] : 'https://gulbenkian.pt/en/agenda/',
      status: 'pending'
    });
  }
}

return events.map(e => ({ json: e }));

// Deduplicate by title + date
// Also fetch existing events from Supabase to avoid re-adding
const items = $input.all().map(i => i.json);

const SB_URL = 'https://waywvckvyizqkuuaecrp.supabase.co';
const SB_KEY = 'sb_publishable_vYRR5942-HlgkWNhuODLdg_eGfOFy4b';

// Fetch existing event titles
let existing = [];
try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: SB_URL + '/rest/v1/events?select=title,event_date&status=in.(approved,pending)',
    headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY }
  });
  existing = res.map(e => e.title.toLowerCase().trim() + '|' + (e.event_date || ''));
} catch(e) {}

const seen = new Set(existing);
const unique = [];
const today = new Date().toISOString().slice(0, 10);

for (const ev of items) {
  if (!ev.title || !ev.event_date) continue;
  if (ev.event_date < today) continue;

  const key = ev.title.toLowerCase().trim() + '|' + ev.event_date;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(ev);
}

return unique.map(e => ({ json: e }));
